// Hinglish-aware tokenizer
function tok(s){
  return String(s||'').toLowerCase().replace(/[^a-z0-9\s]/g,' ').split(/\s+/)
    .filter(t=>t.length>2&&![
      'the','and','for','are','was','that','with','this','from','have','not','they','but','its','you','all',
      'hai','nahi','mein','karo','kare','kiya','kar','tha','thi','the','bhi','aur','yeh','woh',
      'ko','ka','ki','se','per','par','bol','liye','raha','rahi','hain','hoon','gaya','gayi'
    ].includes(t));
}

function buildIdx(docs){
  const idx={},dl={};
  docs.forEach((d,i)=>{
    const toks=tok(d),tf={};
    toks.forEach(t=>{tf[t]=(tf[t]||0)+1;});
    dl[i]=toks.length||1;
    Object.entries(tf).forEach(([t,c])=>{if(!idx[t])idx[t]={};idx[t][i]=c/dl[i];});
  });
  const N=docs.length,idf={};
  Object.entries(idx).forEach(([t,d])=>{idf[t]=Math.log(N/Object.keys(d).length);});
  return{idx,idf};
}

function retrieve(query,docs,index,k=30){
  const toks=tok(query),scores={};
  toks.forEach(t=>{const idf=index.idf[t]||0;Object.entries(index.idx[t]||{}).forEach(([i,tf])=>{scores[i]=(scores[i]||0)+tf*idf;});});
  if(/lava/i.test(query))docs.forEach((d,i)=>{if(/lava/i.test(d))scores[i]=(scores[i]||0)+3;});
  const yr=(query.match(/\b(2024|2025|2026)\b/)||[])[1];
  if(yr)docs.forEach((d,i)=>{if(d.includes(yr))scores[i]=(scores[i]||0)+3;});
  return Object.entries(scores).sort((a,b)=>b[1]-a[1]).slice(0,k).map(([i])=>docs[parseInt(i)]);
}

let VIDX=null;

module.exports = async function(req, res) {
  res.setHeader('Access-Control-Allow-Origin','*');
  res.setHeader('Access-Control-Allow-Methods','POST,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers','Content-Type');

  if(req.method==='OPTIONS') return res.status(200).end();
  if(req.method!=='POST') return res.status(405).json({error:'Method not allowed'});

  const apiKey = process.env.ANTHROPIC_API_KEY;
  if(!apiKey) return res.status(500).json({error:'ANTHROPIC_API_KEY not configured in Vercel environment variables.'});

  const {query} = req.body || {};
  if(!query?.trim()) return res.status(400).json({error:'Empty query'});

  if(!VIDX) VIDX = buildIdx(VERBATIMS);
  const evidence = retrieve(query, VERBATIMS, VIDX, 30);

  const sys = `You are a consumer intelligence analyst for an Indian smartphone brand. You have qualitative interview data from 310 respondents (2024-2026, 17 studies, urban Indian males 18-30) across Delhi, Lucknow, Gwalior, Dehradun, Bangalore, Nagpur, Indore, Bengal, Chennai.

IMPORTANT RULES:
- This is qualitative research. No false statistical precision.
- Never say "X% said" — say "many respondents", "frequently mentioned", "across several cities"
- Use mention counts only as directional signals e.g. "gaming mentioned by ~90 respondents"
- Lead with narrative insight, back with specific verbatims
- Cite respondent names and cities for credibility
- Be strategic and actionable, not just descriptive
- When relevant, connect hardware specs to emotional context (aspiration, anxiety, peer pressure, life goals)`;

  const userMsg = CORPUS_SUMMARY + "\n\n=== SELECTED EVIDENCE (top 30) ===\n" + evidence.join("\n") + "\n\n=== QUERY ===\n" + query;

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01'
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 1200,
        system: sys,
        messages: [{role:'user', content: userMsg}]
      })
    });
    const data = await r.json();
    return res.status(200).json(data);
  } catch(e) {
    return res.status(500).json({error: e.message});
  }
};
